Javascript.validate:
var val = Services.getValue(UnpaidAmnt.dataBinding);
var err = validateCurrencyValue(val, 999999.99);
if( null == err)
{	Services.setValue(UnpaidAmnt.dataBinding, WPU.formatToTwoDP(val));
}

return err;

