function DefaultCurrency627() {}
DefaultCurrency627.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency627.tabIndex = -1;
DefaultCurrency627.maxLength = 1;
DefaultCurrency627.isReadOnly = function(){return true;}
DefaultCurrency627.isTemporary = function(){return true;}
DefaultCurrency627.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency627.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
